// marshalCorpusCorpusDraftResultToCorpusDraftResultResponseBody builds a value
// of type *CorpusDraftResultResponseBody from a value of type
// *corpus.CorpusDraftResult.
func marshalCorpusCorpusDraftResultToCorpusDraftResultResponseBody(v *corpus.CorpusDraftResult) *CorpusDraftResultResponseBody {
	res := &CorpusDraftResultResponseBody{
		ID:              v.ID,
		ProjectID:       v.ProjectID,
		FilePath:        v.FilePath,
		Title:           v.Title,
		Content:         v.Content,
		OriginalContent: v.OriginalContent,
		Operation:       v.Operation,
		Status:          v.Status,
		Source:          v.Source,
		AuthorType:      v.AuthorType,
		AuthorUserID:    v.AuthorUserID,
		AgentName:       v.AgentName,
		CommitSha:       v.CommitSha,
		CreatedAt:       v.CreatedAt,
		UpdatedAt:       v.UpdatedAt,
	}
	if v.Labels != nil {
		res.Labels = make([]string, len(v.Labels))
		for i, val := range v.Labels {
			res.Labels[i] = val
		}
	}

	return res
}

